    from_sequence: Option<u64>,
    /// Max events to return (default 256, max 10000)
    limit: Option<usize>,
}

#[derive(Debug, Deserialize, Default, IntoParams)]
struct StreamQuery {
    /// Branch name (defaults to "main")
    branch: Option<String>,
