  1→use std::sync::Arc;
  2→
  3→use aios_protocol::{
  4→    EventKind, EventRecord, KernelError, ModelCompletion, ModelCompletionRequest, ModelDirective,
  5→    ModelProviderPort, ModelStopReason, TokenUsage, ToolCall,
  6→};
  7→use arcan_core::protocol::{
  8→    ChatMessage, ModelDirective as ArcanDirective, ModelStopReason as ArcanStopReason,
  9→};
 10→use arcan_core::runtime::{Provider, ProviderRequest, SwappableProviderHandle};
 11→use arcan_core::state::AppState;
 12→use async_trait::async_trait;
 13→use tokio::sync::broadcast;
 14→use tracing::Instrument;
 15→
 16→use crate::autonomic::{EconomicGateHandle, EconomicMode};
 17→
 18→/// Shared handle for the runtime broadcast sender.
 19→/// Starts as `None` (before the runtime is created) and is filled in
 20→/// once `KernelRuntime::event_sender()` is available.
 21→pub type StreamingSenderHandle = Arc<std::sync::Mutex<Option<broadcast::Sender<EventRecord>>>>;
 22→
 23→#[derive(Clone)]
 24→pub struct ArcanProviderAdapter {
 25→    handle: SwappableProviderHandle,
 26→    tools: Vec<arcan_core::protocol::ToolDefinition>,
 27→    streaming_sender: StreamingSenderHandle,
 28→    economic_handle: Option<EconomicGateHandle>,
 29→}
 30→
 31→impl ArcanProviderAdapter {
 32→    /// Create from a plain provider Arc (backward compatible).
 33→    /// Wraps it in a SwappableProviderHandle internally.
 34→    pub fn new(
 35→        provider: Arc<dyn Provider>,
 36→        tools: Vec<arcan_core::protocol::ToolDefinition>,
 37→        streaming_sender: StreamingSenderHandle,
 38→    ) -> Self {
 39→        Self {
 40→            handle: Arc::new(std::sync::RwLock::new(provider)),
 41→            tools,
 42→            streaming_sender,
 43→            economic_handle: None,
 44→        }
 45→    }
 46→
 47→    /// Create from a pre-built swappable handle (for live provider switching).
 48→    pub fn from_handle(
 49→        handle: SwappableProviderHandle,
 50→        tools: Vec<arcan_core::protocol::ToolDefinition>,
 51→        streaming_sender: StreamingSenderHandle,
 52→    ) -> Self {
 53→        Self {
 54→            handle,
 55→            tools,
 56→            streaming_sender,
 57→            economic_handle: None,
 58→        }
 59→    }
 60→
 61→    /// Attach an economic gate handle for advisory token capping.
 62→    ///
 63→    /// When set, the provider will consult economic gates before each model call:
 64→    /// - **Hibernate**: Block the call entirely (return error).
 65→    /// - **Hustle**: Cap `max_tokens` to `gates.max_tokens_next_turn`.
 66→    /// - **Conserving**: Advisory log, cap tokens if set.
 67→    /// - **Sovereign**: No restrictions.
 68→    pub fn with_economic_handle(mut self, handle: EconomicGateHandle) -> Self {
 69→        self.economic_handle = Some(handle);
 70→        self
 71→    }
 72→}
 73→
 74→fn to_stop_reason(stop_reason: ArcanStopReason) -> ModelStopReason {
 75→    match stop_reason {
 76→        ArcanStopReason::EndTurn => ModelStopReason::Completed,
 77→        ArcanStopReason::ToolUse => ModelStopReason::ToolCall,
 78→        ArcanStopReason::NeedsUser => ModelStopReason::Cancelled,
 79→        ArcanStopReason::MaxTokens => ModelStopReason::MaxIterations,
 80→        ArcanStopReason::Safety => ModelStopReason::Error,
 81→        ArcanStopReason::Unknown => ModelStopReason::Other("unknown".to_owned()),
 82→    }
 83→}
 84→
 85→#[async_trait]
 86→impl ModelProviderPort for ArcanProviderAdapter {
 87→    async fn complete(
 88→        &self,
 89→        request: ModelCompletionRequest,
 90→    ) -> Result<ModelCompletion, KernelError> {
 91→        // Consult economic gates (advisory — if handle is absent, proceed normally).
 92→        if let Some(ref handle) = self.economic_handle {
 93→            let gates = handle.read().await;
 94→            if let Some(ref gates) = *gates {
 95→                match gates.economic_mode {
 96→                    EconomicMode::Hibernate => {
 97→                        tracing::warn!(
 98→                            session = %request.session_id,
 99→                            "Autonomic: Hibernate mode — blocking model call"
100→                        );
101→                        return Err(KernelError::Runtime(
102→                            "model call blocked: Autonomic Hibernate mode active".to_owned(),
103→                        ));
104→                    }
105→                    EconomicMode::Hustle => {
106→                        if let Some(max) = gates.max_tokens_next_turn {
107→                            tracing::info!(
108→                                session = %request.session_id,
109→                                max_tokens = max,
110→                                "Autonomic: Hustle mode — capping tokens"
111→                            );
112→                        }
113→                    }
114→                    EconomicMode::Conserving => {
115→                        tracing::debug!(
116→                            session = %request.session_id,
117→                            "Autonomic: Conserving mode"
118→                        );
119→                    }
120→                    EconomicMode::Sovereign => {}
121→                }
122→            }
123→        }
124→
125→        let provider_request = ProviderRequest {
126→            run_id: request.run_id.as_str().to_owned(),
127→            session_id: request.session_id.as_str().to_owned(),
128→            iteration: request.step_index + 1,
129→            messages: vec![ChatMessage::user(request.objective)],
130→            tools: self.tools.clone(),
131→            state: AppState::default(),
132→        };
133→
134→        let provider = self
135→            .handle
136→            .read()
137→            .unwrap_or_else(std::sync::PoisonError::into_inner)
138→            .clone();
139→        let provider_name = provider.name().to_owned();
140→        let use_streaming = provider.supports_streaming();
141→        let sender = self
142→            .streaming_sender
143→            .lock()
144→            .unwrap_or_else(std::sync::PoisonError::into_inner)
145→            .clone();
146→
147→        let session_id = request.session_id.clone();
148→        let branch_id = request.branch_id.clone();
149→
150→        // Create a GenAI chat span for this provider call.
151→        let chat_span = vigil::spans::chat_span(&provider_name, &provider_name, None, None);
152→
153→        // The Arcan Provider trait is synchronous and may use reqwest::blocking,
154→        // which panics if called directly on a tokio worker thread.
155→        // Wrap in spawn_blocking to run on a dedicated thread.
156→        let turn = tokio::task::spawn_blocking(move || {
157→            if use_streaming {
158→                if let Some(sender) = sender {
159→                    let sess = session_id;
160→                    let branch = branch_id;
161→                    return provider.complete_streaming(&provider_request, &|text| {
162→                        let event = EventRecord::new(
163→                            sess.clone(),
164→                            branch.clone(),
165→                            0, // sequence 0 = ephemeral, not persisted
166→                            EventKind::AssistantTextDelta {
167→                                delta: text.to_owned(),
168→                                index: None,
169→                            },
170→                        );
171→                        let _ = sender.send(event);
172→                    });
173→                }
174→            }
175→            provider.complete(&provider_request)
176→        })
177→        .instrument(chat_span.clone())
178→        .await
179→        .map_err(|join_error: tokio::task::JoinError| {
180→            KernelError::Runtime(format!("provider task panicked: {join_error}"))
181→        })?
182→        .map_err(|error| KernelError::Runtime(error.to_string()))?;
183→
184→        // Record stop reason on the chat span.
185→        let stop_reason = to_stop_reason(turn.stop_reason);
186→        let reason_str = match &stop_reason {
187→            ModelStopReason::Completed => "stop",
188→            ModelStopReason::ToolCall => "tool_calls",
189→            ModelStopReason::MaxIterations => "max_tokens",
190→            ModelStopReason::Cancelled => "cancelled",
191→            ModelStopReason::Error => "error",
192→            ModelStopReason::Other(s) => s.as_str(),
193→        };
194→        vigil::spans::record_finish_reason(&chat_span, reason_str);
195→
196→        let mut directives = Vec::new();
197→        let mut final_answer = None;
198→        for directive in turn.directives {
199→            match directive {
200→                ArcanDirective::Text { delta } => {
201→                    directives.push(ModelDirective::TextDelta { delta, index: None });
202→                }
203→                ArcanDirective::ToolCall { call } => {
204→                    directives.push(ModelDirective::ToolCall {
205→                        call: ToolCall {
206→                            call_id: call.call_id,
207→                            tool_name: call.tool_name,
208→                            input: call.input,
209→                            requested_capabilities: Vec::new(),
210→                        },
211→                    });
212→                }
213→                ArcanDirective::StatePatch { patch } => {
214→                    directives.push(ModelDirective::Message {
215→                        role: "system".to_owned(),
216→                        content: serde_json::to_string(&patch.patch)
217→                            .unwrap_or_else(|_| "{}".to_owned()),
218→                    });
219→                }
220→                ArcanDirective::FinalAnswer { text } => {
221→                    final_answer = Some(text.clone());
222→                    directives.push(ModelDirective::Message {
223→                        role: "assistant".to_owned(),
224→                        content: text,
225→                    });
226→                }
227→            }
228→        }
229→
230→        let usage = turn.usage.map(|usage| TokenUsage {
231→            prompt_tokens: usage.input_tokens as u32,
232→            completion_tokens: usage.output_tokens as u32,
233→            total_tokens: usage.total() as u32,
234→        });
235→
236→        // Record token usage on the chat span.
237→        if let Some(ref usage) = usage {
238→            vigil::spans::record_token_usage(&chat_span, usage);
239→        }
240→
241→        Ok(ModelCompletion {
242→            provider: provider_name.clone(),
243→            model: provider_name,
244→            directives,
245→            stop_reason,
246→            usage,
247→            final_answer,
248→        })
249→    }
250→}
