  1→use aios_protocol::{
  2→    KernelError, ToolExecutionReport, ToolExecutionRequest, ToolHarnessPort, ToolOutcome, ToolRunId,
  3→};
  4→use arcan_core::protocol::ToolCall;
  5→use arcan_core::runtime::{ToolContext, ToolRegistry};
  6→use async_trait::async_trait;
  7→use std::sync::Arc;
  8→use tracing::Instrument;
  9→
 10→#[async_trait]
 11→pub trait ToolHarnessObserver: Send + Sync {
 12→    async fn post_execute(&self, session_id: String, tool_name: String);
 13→}
 14→
 15→#[derive(Clone)]
 16→pub struct ArcanHarnessAdapter {
 17→    registry: ToolRegistry,
 18→    observers: Vec<Arc<dyn ToolHarnessObserver>>,
 19→}
 20→
 21→impl ArcanHarnessAdapter {
 22→    pub fn new(registry: ToolRegistry) -> Self {
 23→        Self {
 24→            registry,
 25→            observers: Vec::new(),
 26→        }
 27→    }
 28→
 29→    pub fn with_observer(mut self, observer: Arc<dyn ToolHarnessObserver>) -> Self {
 30→        self.observers.push(observer);
 31→        self
 32→    }
 33→}
 34→
 35→#[async_trait]
 36→impl ToolHarnessPort for ArcanHarnessAdapter {
 37→    async fn execute(
 38→        &self,
 39→        request: ToolExecutionRequest,
 40→    ) -> Result<ToolExecutionReport, KernelError> {
 41→        let tool = self
 42→            .registry
 43→            .get(&request.call.tool_name)
 44→            .ok_or_else(|| KernelError::ToolNotFound(request.call.tool_name.clone()))?;
 45→
 46→        let arcan_call = ToolCall {
 47→            call_id: request.call.call_id.clone(),
 48→            tool_name: request.call.tool_name.clone(),
 49→            input: request.call.input.clone(),
 50→        };
 51→        let context = ToolContext {
 52→            run_id: format!("run-{}", request.call.call_id),
 53→            session_id: request.session_id.as_str().to_owned(),
 54→            iteration: 1,
 55→        };
 56→
 57→        let tool_span = vigil::spans::tool_span(&request.call.tool_name, &request.call.call_id);
 58→        let result = {
 59→            let _guard = tool_span.enter();
 60→            tool.execute(&arcan_call, &context)
 61→                .map_err(|error| KernelError::Runtime(error.to_string()))?
 62→        };
 63→        let exit_status = if result.is_error { 1 } else { 0 };
 64→        let outcome = if result.is_error {
 65→            vigil::spans::record_tool_status(&tool_span, "error");
 66→            ToolOutcome::Failure {
 67→                error: result
 68→                    .output
 69→                    .get("error")
 70→                    .and_then(|value| value.as_str())
 71→                    .map(ToOwned::to_owned)
 72→                    .unwrap_or_else(|| "tool execution failed".to_owned()),
 73→            }
 74→        } else {
 75→            vigil::spans::record_tool_status(&tool_span, "ok");
 76→            ToolOutcome::Success {
 77→                output: result.output,
 78→            }
 79→        };
 80→
 81→        for observer in &self.observers {
 82→            observer
 83→                .as_ref()
 84→                .post_execute(
 85→                    request.session_id.as_str().to_owned(),
 86→                    arcan_call.tool_name.clone(),
 87→                )
 88→                .instrument(tool_span.clone())
 89→                .await;
 90→        }
 91→
 92→        Ok(ToolExecutionReport {
 93→            tool_run_id: ToolRunId::default(),
 94→            call_id: arcan_call.call_id,
 95→            tool_name: arcan_call.tool_name,
 96→            exit_status,
 97→            duration_ms: 0,
 98→            outcome,
 99→        })
100→    }
101→}
