  1→//! Vigil — observability foundation for the Life Agent OS.
  2→//!
  3→//! Provides a unified telemetry pipeline combining structured logging,
  4→//! OpenTelemetry distributed tracing, and metrics collection with
  5→//! GenAI semantic conventions.
  6→//!
  7→//! # Usage
  8→//!
  9→//! ```no_run
 10→//! use vigil::{VigConfig, init_telemetry};
 11→//!
 12→//! # fn main() -> Result<(), vigil::VigError> {
 13→//! let config = VigConfig::for_service("arcan").with_env_overrides();
 14→//! let _guard = init_telemetry(config)?;
 15→//!
 16→//! // All tracing macros now emit structured logs and (if configured) OTel spans.
 17→//! tracing::info!("Agent OS started");
 18→//! # Ok(())
 19→//! # }
 20→//! ```
 21→//!
 22→//! If no OTLP endpoint is configured, Vigil degrades gracefully to
 23→//! structured logging only via `tracing-subscriber`.
 24→
 25→pub mod config;
 26→pub mod metrics;
 27→pub mod semconv;
 28→pub mod spans;
 29→
 30→pub use config::{LogFormat, OtlpProtocol, VigConfig};
 31→pub use metrics::GenAiMetrics;
 32→
 33→use opentelemetry::global;
 34→use opentelemetry::trace::TracerProvider as _;
 35→use opentelemetry_otlp::WithExportConfig as _;
 36→use opentelemetry_otlp::WithTonicConfig as _;
 37→use opentelemetry_sdk::Resource;
 38→use opentelemetry_sdk::metrics::SdkMeterProvider;
 39→use opentelemetry_sdk::trace::SdkTracerProvider;
 40→use tracing_subscriber::EnvFilter;
 41→use tracing_subscriber::prelude::*;
 42→
 43→/// Errors during telemetry initialization.
 44→#[derive(Debug, thiserror::Error)]
 45→pub enum VigError {
 46→    #[error("failed to build OTLP span exporter: {0}")]
 47→    SpanExporter(String),
 48→
 49→    #[error("failed to build OTLP metric exporter: {0}")]
 50→    MetricExporter(String),
 51→
 52→    #[error("failed to initialize tracing subscriber: {0}")]
 53→    Subscriber(String),
 54→}
 55→
 56→/// Guard that flushes and shuts down telemetry providers on drop.
 57→///
 58→/// Hold this in your `main()` for the lifetime of the application.
 59→pub struct VigGuard {
 60→    tracer_provider: Option<SdkTracerProvider>,
 61→    meter_provider: Option<SdkMeterProvider>,
 62→}
 63→
 64→impl Drop for VigGuard {
 65→    fn drop(&mut self) {
 66→        if let Some(ref tp) = self.tracer_provider {
 67→            let _ = tp.shutdown();
 68→        }
 69→        if let Some(ref mp) = self.meter_provider {
 70→            let _ = mp.shutdown();
 71→        }
 72→    }
 73→}
 74→
 75→/// Initialize the Vigil telemetry pipeline.
 76→///
 77→/// Sets up:
 78→/// 1. `tracing-subscriber` with `EnvFilter` + formatted output (pretty or JSON)
 79→/// 2. `tracing-opentelemetry` layer bridging to OTel SDK (if endpoint configured)
 80→/// 3. OTLP exporter for traces (if endpoint configured)
 81→/// 4. OTLP exporter for metrics (if endpoint configured)
 82→///
 83→/// Returns a [`VigGuard`] that flushes telemetry on drop.
 84→///
 85→/// If no OTLP endpoint is set, only structured logging is configured.
 86→pub fn init_telemetry(config: VigConfig) -> Result<VigGuard, VigError> {
 87→    let env_filter = EnvFilter::try_from_default_env().unwrap_or_else(|_| EnvFilter::new("info"));
 88→
 89→    if let Some(ref endpoint) = config.otlp_endpoint {
 90→        init_with_otel(config.clone(), endpoint, env_filter)
 91→    } else {
 92→        init_logging_only(&config, env_filter)
 93→    }
 94→}
 95→
 96→/// Initialize with full OTel pipeline.
 97→fn init_with_otel(
 98→    config: VigConfig,
 99→    endpoint: &str,
100→    env_filter: EnvFilter,
101→) -> Result<VigGuard, VigError> {
102→    let resource = Resource::builder()
103→        .with_service_name(config.service_name.clone())
104→        .build();
105→
106→    // Build tracer provider
107→    let tracer_provider = build_tracer_provider(&config, endpoint, resource.clone())?;
108→    global::set_tracer_provider(tracer_provider.clone());
109→
110→    // Build meter provider
111→    let meter_provider = build_meter_provider(&config, endpoint, resource)?;
112→    global::set_meter_provider(meter_provider.clone());
113→
114→    // Create OTel tracing layer
115→    let tracer = tracer_provider.tracer(config.service_name.clone());
116→    let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);
117→
118→    // Build subscriber with OTel layer + fmt layer
119→    let registry = tracing_subscriber::registry().with(otel_layer);
120→
121→    match config.log_format {
122→        LogFormat::Json => {
123→            let fmt_layer = tracing_subscriber::fmt::layer()
124→                .json()
125→                .with_filter(env_filter);
126→            registry.with(fmt_layer).try_init().map_err(
127→                |e: tracing_subscriber::util::TryInitError| VigError::Subscriber(e.to_string()),
128→            )?;
129→        }
130→        LogFormat::Pretty => {
131→            let fmt_layer = tracing_subscriber::fmt::layer().with_filter(env_filter);
132→            registry.with(fmt_layer).try_init().map_err(
133→                |e: tracing_subscriber::util::TryInitError| VigError::Subscriber(e.to_string()),
134→            )?;
135→        }
136→    }
137→
138→    Ok(VigGuard {
139→        tracer_provider: Some(tracer_provider),
140→        meter_provider: Some(meter_provider),
141→    })
142→}
143→
144→/// Initialize with logging only (no OTel export).
145→fn init_logging_only(config: &VigConfig, env_filter: EnvFilter) -> Result<VigGuard, VigError> {
146→    match config.log_format {
147→        LogFormat::Json => {
148→            tracing_subscriber::registry()
149→                .with(
150→                    tracing_subscriber::fmt::layer()
151→                        .json()
152→                        .with_filter(env_filter),
153→                )
154→                .try_init()
155→                .map_err(|e: tracing_subscriber::util::TryInitError| {
156→                    VigError::Subscriber(e.to_string())
157→                })?;
158→        }
159→        LogFormat::Pretty => {
160→            tracing_subscriber::registry()
161→                .with(tracing_subscriber::fmt::layer().with_filter(env_filter))
162→                .try_init()
163→                .map_err(|e: tracing_subscriber::util::TryInitError| {
164→                    VigError::Subscriber(e.to_string())
165→                })?;
166→        }
167→    }
168→
169→    Ok(VigGuard {
170→        tracer_provider: None,
171→        meter_provider: None,
172→    })
173→}
174→
175→/// Build an OTLP tracer provider.
176→fn build_tracer_provider(
177→    config: &VigConfig,
178→    endpoint: &str,
179→    resource: Resource,
180→) -> Result<SdkTracerProvider, VigError> {
181→    let exporter = match config.otlp_protocol {
182→        OtlpProtocol::Grpc => {
183→            let mut builder = opentelemetry_otlp::SpanExporter::builder()
184→                .with_tonic()
185→                .with_endpoint(endpoint);
186→
187→            if !config.otlp_headers.is_empty() {
188→                let mut metadata = tonic::metadata::MetadataMap::new();
189→                for (key, value) in &config.otlp_headers {
190→                    if let (Ok(k), Ok(v)) = (
191→                        key.parse::<tonic::metadata::MetadataKey<tonic::metadata::Ascii>>(),
192→                        value.parse::<tonic::metadata::MetadataValue<tonic::metadata::Ascii>>(),
193→                    ) {
194→                        metadata.insert(k, v);
195→                    }
196→                }
197→                builder = builder.with_metadata(metadata);
198→            }
199→
200→            builder
201→                .build()
202→                .map_err(|e| VigError::SpanExporter(e.to_string()))?
203→        }
204→        OtlpProtocol::Http => opentelemetry_otlp::SpanExporter::builder()
205→            .with_http()
206→            .with_endpoint(endpoint)
207→            .build()
208→            .map_err(|e| VigError::SpanExporter(e.to_string()))?,
209→    };
210→
211→    let provider = SdkTracerProvider::builder()
212→        .with_batch_exporter(exporter)
213→        .with_resource(resource)
214→        .build();
215→
216→    Ok(provider)
217→}
218→
219→/// Build an OTLP meter provider.
220→fn build_meter_provider(
221→    config: &VigConfig,
222→    endpoint: &str,
223→    resource: Resource,
224→) -> Result<SdkMeterProvider, VigError> {
225→    let exporter = match config.otlp_protocol {
226→        OtlpProtocol::Grpc => {
227→            let mut builder = opentelemetry_otlp::MetricExporter::builder()
228→                .with_tonic()
229→                .with_endpoint(endpoint);
230→
231→            if !config.otlp_headers.is_empty() {
232→                let mut metadata = tonic::metadata::MetadataMap::new();
233→                for (key, value) in &config.otlp_headers {
234→                    if let (Ok(k), Ok(v)) = (
235→                        key.parse::<tonic::metadata::MetadataKey<tonic::metadata::Ascii>>(),
236→                        value.parse::<tonic::metadata::MetadataValue<tonic::metadata::Ascii>>(),
237→                    ) {
238→                        metadata.insert(k, v);
239→                    }
240→                }
241→                builder = builder.with_metadata(metadata);
242→            }
243→
244→            builder
245→                .build()
246→                .map_err(|e| VigError::MetricExporter(e.to_string()))?
247→        }
248→        OtlpProtocol::Http => opentelemetry_otlp::MetricExporter::builder()
249→            .with_http()
250→            .with_endpoint(endpoint)
251→            .build()
252→            .map_err(|e| VigError::MetricExporter(e.to_string()))?,
253→    };
254→
255→    let provider = SdkMeterProvider::builder()
256→        .with_periodic_exporter(exporter)
257→        .with_resource(resource)
258→        .build();
259→
260→    Ok(provider)
261→}
