  1→//! HTTP router for the Autonomic API.
  2→//!
  3→//! Endpoints:
  4→//! - `GET /health` — health check
  5→//! - `GET /gating/{session_id}` — evaluate rules and return gating profile
  6→//! - `GET /projection/{session_id}` — return raw homeostatic state
  7→
  8→use axum::extract::{Path, State};
  9→use axum::http::StatusCode;
 10→use axum::response::Json;
 11→use axum::{Router, routing::get};
 12→use serde::Serialize;
 13→use tracing::instrument;
 14→
 15→use autonomic_controller::evaluate;
 16→use autonomic_core::gating::{AutonomicGatingProfile, HomeostaticState};
 17→
 18→use crate::state::AppState;
 19→
 20→/// Build the axum router with all endpoints.
 21→pub fn build_router(state: AppState) -> Router {
 22→    Router::new()
 23→        .route("/health", get(health))
 24→        .route("/gating/{session_id}", get(get_gating))
 25→        .route("/projection/{session_id}", get(get_projection))
 26→        .with_state(state)
 27→}
 28→
 29→/// Health check response.
 30→#[derive(Serialize)]
 31→struct HealthResponse {
 32→    status: &'static str,
 33→    version: &'static str,
 34→}
 35→
 36→async fn health() -> Json<HealthResponse> {
 37→    Json(HealthResponse {
 38→        status: "ok",
 39→        version: env!("CARGO_PKG_VERSION"),
 40→    })
 41→}
 42→
 43→/// Gating response with staleness indicator.
 44→#[derive(Serialize)]
 45→pub struct GatingResponse {
 46→    pub session_id: String,
 47→    pub profile: AutonomicGatingProfile,
 48→    pub last_event_seq: u64,
 49→    pub last_event_ms: u64,
 50→}
 51→
 52→#[instrument(skip(state), fields(life.session_id = %session_id))]
 53→async fn get_gating(
 54→    State(state): State<AppState>,
 55→    Path(session_id): Path<String>,
 56→) -> Result<Json<GatingResponse>, StatusCode> {
 57→    let homeostatic_state = get_or_bootstrap(&state, &session_id).await;
 58→
 59→    let profile = evaluate(&homeostatic_state, &state.rules);
 60→
 61→    Ok(Json(GatingResponse {
 62→        session_id,
 63→        profile,
 64→        last_event_seq: homeostatic_state.last_event_seq,
 65→        last_event_ms: homeostatic_state.last_event_ms,
 66→    }))
 67→}
 68→
 69→/// Projection response.
 70→#[derive(Serialize)]
 71→pub struct ProjectionResponse {
 72→    pub session_id: String,
 73→    pub state: HomeostaticState,
 74→    pub found: bool,
 75→}
 76→
 77→#[instrument(skip(state), fields(life.session_id = %session_id))]
 78→async fn get_projection(
 79→    State(state): State<AppState>,
 80→    Path(session_id): Path<String>,
 81→) -> Json<ProjectionResponse> {
 82→    let projections = state.projections.read().await;
 83→
 84→    let (homeostatic_state, found) = match projections.get(&session_id) {
 85→        Some(s) => (s.clone(), true),
 86→        None => (HomeostaticState::for_agent(&session_id), false),
 87→    };
 88→
 89→    Json(ProjectionResponse {
 90→        session_id,
 91→        state: homeostatic_state,
 92→        found,
 93→    })
 94→}
 95→
 96→/// Get projection from cache, or bootstrap from Lago journal if available.
 97→#[instrument(skip(state), fields(life.session_id = %session_id))]
 98→async fn get_or_bootstrap(state: &AppState, session_id: &str) -> HomeostaticState {
 99→    // Fast path: already in projection map
100→    {
101→        let projections = state.projections.read().await;
102→        if let Some(s) = projections.get(session_id) {
103→            return s.clone();
104→        }
105→    }
106→
107→    // Slow path: bootstrap from Lago journal if available
108→    if let Some(journal) = &state.journal {
109→        match autonomic_lago::load_projection(journal.clone(), session_id, "main").await {
110→            Ok(loaded) => {
111→                let mut projections = state.projections.write().await;
112→                projections.insert(session_id.to_owned(), loaded.clone());
113→
114→                // Spawn live subscriber for ongoing updates
115→                let j = journal.clone();
116→                let sid = session_id.to_owned();
117→                let p = state.projections.clone();
118→                tokio::spawn(async move {
119→                    autonomic_lago::subscribe_session(j, sid, "main".into(), p).await;
120→                });
121→
122→                return loaded;
123→            }
124→            Err(e) => {
125→                tracing::warn!(
126→                    session_id = %session_id,
127→                    error = %e,
128→                    "failed to bootstrap projection from Lago"
129→                );
130→            }
131→        }
132→    }
133→
134→    HomeostaticState::for_agent(session_id)
135→}
