  1→//! Semantic convention constants for GenAI and Life Agent OS observability.
  2→//!
  3→//! These follow the [OTel GenAI semantic conventions](https://opentelemetry.io/docs/specs/semconv/gen-ai/)
  4→//! and extend them with Life-specific attributes under the `life.` namespace.
  5→
  6→// ─── GenAI Semantic Conventions ──────────────────────────────────────────────
  7→
  8→/// The name of the operation being performed (e.g. "chat", "text_completion").
  9→pub const GEN_AI_OPERATION_NAME: &str = "gen_ai.operation.name";
 10→
 11→/// The AI system / provider (e.g. "anthropic", "openai").
 12→pub const GEN_AI_SYSTEM: &str = "gen_ai.system";
 13→
 14→/// The model requested (e.g. "claude-sonnet-4-20250514").
 15→pub const GEN_AI_REQUEST_MODEL: &str = "gen_ai.request.model";
 16→
 17→/// Maximum number of tokens the model should generate.
 18→pub const GEN_AI_REQUEST_MAX_TOKENS: &str = "gen_ai.request.max_tokens";
 19→
 20→/// Sampling temperature.
 21→pub const GEN_AI_REQUEST_TEMPERATURE: &str = "gen_ai.request.temperature";
 22→
 23→/// Top-p (nucleus) sampling parameter.
 24→pub const GEN_AI_REQUEST_TOP_P: &str = "gen_ai.request.top_p";
 25→
 26→/// Number of input (prompt) tokens consumed.
 27→pub const GEN_AI_USAGE_INPUT_TOKENS: &str = "gen_ai.usage.input_tokens";
 28→
 29→/// Number of output (completion) tokens generated.
